import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { newEnrollment, findEnrollments, searchEnrollments, findSubjects, findTerms, } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
import CustomToolbarSelectEnrollments from "../components/CustomToolbarSelectEnrollments";
class EnrollmentsPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          subject : 'nn',
          year : 'nn',
          estatus : 'nn',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          subjects:[],
          terms:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            // findEnrollments(obje_results.user.token).then((response) => {
            //     // console.log('data-data', response.data);
            //     this.setState({
            //         ...this.state,
            //         data:response.data,
            //     });
            // }).catch((respError) => {});
            findSubjects(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    subjects:response.data,
                });
            }).catch((respError) => {});
            findTerms(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    terms:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    isValidEmailAddress = (email) => {
        if (/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,4}$/i.test(email)) {
            return true;
        }
        return false;
    }

    rerenderParentCallback = () => {
      findSubjects (this.state.xtoken).then((response) => {
        this.setState({
            ...this.state,
            data:response.data,
        });
      }).catch((respError) => {
      });
    }
    
    handleSubjectInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, subject: v,});
    }
    handleYearInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, year: v,});
    }
    handleEstatusInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, estatus: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        searchEnrollments(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
                // this.forceUpdate();
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:true,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:true,
            });
            console.log('error', error);
        });
    }
    render() {
        const columns = [
            {
              name: 'Id',
              options: {
                display: false
              }
            },
            'Student',
            'Year',
            'Date Enrolled',
        ];

        const data2 = () => {
          let rtn = [];
          this.state.data.map(item => {
            rtn.push([
                item.id,
                item.slabel,
                item.year,
                item.dlabel,
            ]);
          });
          return rtn;
        }
      
        const options = {
            filter: true,
            selectableRows: false,
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            customToolbarSelect: (selectedRows, displayData, setSelectedRows) => (
              <CustomToolbarSelectEnrollments rerenderParentCallback={this.rerenderParentCallback} selectedRows={selectedRows} displayData={displayData} setSelectedRows={setSelectedRows}  originalData={this.state.data} Xtoken={this.state.xtoken}/>
            ),
            downloadOptions: {
                filename: 'school-data-excel-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(data2)}`.trim();
                return val;
              }
      
              return false;
            },
            onRowSelectionChange: (currentRowsSelected, allRows, rowsSelected) => {
              // console.log('currentRowsSelected', currentRowsSelected);
            },
            onRowsDelete: rowsDeleted => {
              // console.log(rowsDeleted, 'were deleted!');
            },
            onChangePage: numberRows => {
              // console.log(numberRows);
            },
            onSearchChange: searchText => {
              // console.log(searchText);
            },
            onColumnSortChange: (column, direction) => {
              // console.log(column, direction);
            },
            onViewColumnsChange: (column, action) => {
              // console.log(column, action);
            },
            onFilterChange: (column, filters) => {
              // console.log(column, filters);
            },
            onCellClick: (cellIndex, rowIndex) => {
              // console.log(cellIndex, rowIndex);
            },
            onRowClick: (rowData, rowState) => {
              // console.log(rowData, rowState);
            },
        };
      return (
        <Page title="Search enrollments" breadcrumbs={[{ name: 'Search', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Search Enrollments {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Subject *</Label>
                      <Input onChange={this.handleSubjectInput} value={this.state.subject} defaultValue={this.state.subject} type="select" name="frm">
                        <option value="nn" disabled={true}>Select Subject</option>
                        {this.state.subjects.map((stt, idx) => (
                            <option value={stt.id}>{stt.label}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Year *</Label>
                      <Input onChange={this.handleYearInput} value={this.state.year} defaultValue={this.state.year} type="select" name="frm">
                        <option value="nn" disabled={true}>Select Year</option>
                        {this.state.terms.map((stt, idx) => (
                            <option value={stt.year}>{stt.year + ' - ' + stt.label}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Enrollment Status *</Label>
                      <Input onChange={this.handleEstatusInput} value={this.state.estatus} defaultValue={this.state.estatus} type="select" name="frm">
                        <option value="nn" disabled={true}>Select Status</option>
                        <option value="enrolled">Enrolled</option>
                        <option value="completed">Completed</option>
                        <option value="dropped">Dropped</option>
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>              
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Search now</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'Subject enrollments'}
                    data={this.state.data.map(item => {
                      return [
                        item.id,
                        item.slabel,
                        item.year,
                        item.dlabel,
                      ]
                    })} columns={columns} options={options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default EnrollmentsPage;
